// Merge rank-prioritized results with age-based fallback
// If rank-based RPC returned data, use that; otherwise fall back to age-based query
const ranked = $('Fetch Stale Posts (Rank Prioritized)').first()?.json;
const fallback = $('Fetch Stale Posts (Age Fallback)').first()?.json;

let posts = [];

// Check if ranked query succeeded (RPC might not exist yet)
if (ranked && !ranked.error && Array.isArray(ranked)) {
  posts = ranked;
} else if (Array.isArray(ranked)) {
  posts = ranked;
} else {
  // Fall back to age-based ordering
  const fb = $('Fetch Stale Posts (Age Fallback)').all();
  if (Array.isArray(fb[0]?.json) && fb[0].json.length > 0) {
    posts = fb[0].json;
  } else if (fb.length > 0 && fb[0]?.json?.id) {
    posts = fb.map(i => i.json);
  }
}

// Limit to 3 per run (Claude API budget control)
const limited = posts.slice(0, 3);
const totalStale = posts.length;

if (limited.length === 0) {
  return [{ json: { _empty: true, total_found: 0, remaining_titles: [] } }];
}

// Track remaining candidates for Telegram summary
const remaining = posts.slice(3, 6).map(p => p.title || p.slug);

return limited.map((p, i) => ({
  json: {
    ...p,
    _total_stale: totalStale,
    _remaining_titles: i === 0 ? remaining : []
  }
}));

// Quality Gate: extract refreshed content, validate title/meta/word count
const input = $input.first().json;
const post = $('Has Posts?').first().json;

// Check for API errors
if (input.error || !input.content || !input.content[0]?.text) {
  return [{ json: { _skip: true, reason: 'api_error', id: post.id, slug: post.slug, title: post.title } }];
}

const text = input.content[0].text;

// Parse structured response
let title = post.title;
let metaDesc = post.meta_description || '';
let content = text;

const titleMatch = text.match(/^TITLE:\s*(.+)$/m);
if (titleMatch) {
  title = titleMatch[1].trim().substring(0, 65);
}

const metaMatch = text.match(/^META_DESC:\s*(.+)$/m);
if (metaMatch) {
  metaDesc = metaMatch[1].trim().substring(0, 155);
}

const contentMatch = text.match(/^CONTENT:\n([\s\S]+)$/m);
if (contentMatch) {
  content = contentMatch[1].trim();
} else {
  // Fallback: strip TITLE/META lines from the text
  content = text
    .replace(/^TITLE:.*$/m, '')
    .replace(/^META_DESC:.*$/m, '')
    .replace(/^CONTENT:$/m, '')
    .trim();
}

const wordCount = content.split(/\s+/).length;

// Quality checks
if (wordCount < 800) {
  return [{ json: { _skip: true, reason: 'too_short_' + wordCount + '_words', id: post.id, slug: post.slug, title: post.title } }];
}

if (title.length > 65) {
  title = title.substring(0, 65);
}

if (metaDesc.length > 155) {
  metaDesc = metaDesc.substring(0, 155);
}

return [{ json: {
  _skip: false,
  id: post.id,
  slug: post.slug,
  title: title,
  original_title: post.title,
  refreshed_content: content,
  meta_description: metaDesc,
  word_count: wordCount,
  _total_stale: post._total_stale || 0,
  _remaining_titles: post._remaining_titles || []
} }];

// Aggregate results for Telegram summary
const allQG = $('Quality Gate').all();
const mergeNode = $('Merge & Limit to 3').all();

const totalStale = mergeNode[0]?.json?._total_stale || mergeNode.filter(i => !i.json._empty).length;
const remaining = mergeNode[0]?.json?._remaining_titles || [];

const refreshed = allQG.filter(i => !i.json._skip);
const skipped = allQG.filter(i => i.json._skip && i.json.reason !== 'no_posts');
const noPostsFound = allQG.some(i => i.json.reason === 'no_posts' || i.json._empty);

let msg = '\ud83d\udcdd **CONTENT REFRESH** (TG-50)\n\n';

if (noPostsFound && refreshed.length === 0) {
  msg += 'No stale posts found (all content < 90 days old). Nothing to refresh this week.\n';
} else {
  msg += `Found ${totalStale} stale post(s).\n`;
  msg += `Refreshed ${refreshed.length} this week.\n\n`;

  if (refreshed.length > 0) {
    msg += refreshed.map(i => `\u2705 ${i.json.title} (${i.json.word_count} words)`).join('\n') + '\n';
  }

  if (skipped.length > 0) {
    msg += '\n' + skipped.map(i => `\u274c Skipped: ${i.json.slug || i.json.title} (${i.json.reason})`).join('\n') + '\n';
  }

  if (remaining.length > 0) {
    msg += `\n\ud83d\udccb Next candidates:\n` + remaining.map(t => `  \u2022 ${t}`).join('\n');
  }
}

return [{ json: { message: msg } }];
